EsAttentionLnQKVOutput EsAttentionLnQKV(EsbTensor *x, EsbTensor *kernel_query, EsbTensor *kernel_key, EsbTensor *kernel_value, EsbTensor *gamma, EsbTensor *beta, EsbTensor *bias_query, EsbTensor *bias_key, EsbTensor *bias_value, float epsilon, bool trans_a, bool trans_b) {
GE_ASSERT_NOTNULL(x);
GE_ASSERT_NOTNULL(kernel_query);
GE_ASSERT_NOTNULL(kernel_key);
GE_ASSERT_NOTNULL(kernel_value);
GE_ASSERT_NOTNULL(gamma);
GE_ASSERT_NOTNULL(beta);
auto &graph = x->GetOwner();

auto desc = af::CompliantOpDescBuilder().OpType("AttentionLnQKV")
.Name(("AttentionLnQKV_" + std::to_string(graph.NextNodeIndex())).c_str())
.IrDefInputs({
{"x", af::kIrInputRequired, ""},
{"kernel_query", af::kIrInputRequired, ""},
{"kernel_key", af::kIrInputRequired, ""},
{"kernel_value", af::kIrInputRequired, ""},
{"gamma", af::kIrInputRequired, ""},
{"beta", af::kIrInputRequired, ""},
{"bias_query", af::kIrInputOptional, ""},
{"bias_key", af::kIrInputOptional, ""},
{"bias_value", af::kIrInputOptional, ""},
})
.IrDefOutputs({
{"norm", af::kIrOutputRequired, ""},
{"query_output", af::kIrOutputRequired, ""},
{"key_output", af::kIrOutputRequired, ""},
{"value_output", af::kIrOutputRequired, ""},
{"mean", af::kIrOutputRequired, ""},
{"variance", af::kIrOutputRequired, ""},
})
.IrDefAttrs({
{
"epsilon",
af::kAttrOptional,
"VT_FLOAT",
af::AnyValue::CreateFrom(static_cast<float>(epsilon))
},
{
"trans_a",
af::kAttrOptional,
"VT_BOOL",
af::AnyValue::CreateFrom(static_cast<bool>(trans_a))
},
{
"trans_b",
af::kAttrOptional,
"VT_BOOL",
af::AnyValue::CreateFrom(static_cast<bool>(trans_b))
},
})
.Build();
GE_ASSERT_NOTNULL(desc);
auto node = graph.GetComputeGraph()->AddNode(desc);
GE_ASSERT_NOTNULL(node);

GE_ASSERT_GRAPH_SUCCESS(af::GraphUtils::AddEdge(x->GetAnchor(), node->GetInDataAnchor(0)));
GE_ASSERT_GRAPH_SUCCESS(af::GraphUtils::AddEdge(kernel_query->GetAnchor(), node->GetInDataAnchor(1)));
GE_ASSERT_GRAPH_SUCCESS(af::GraphUtils::AddEdge(kernel_key->GetAnchor(), node->GetInDataAnchor(2)));
GE_ASSERT_GRAPH_SUCCESS(af::GraphUtils::AddEdge(kernel_value->GetAnchor(), node->GetInDataAnchor(3)));
GE_ASSERT_GRAPH_SUCCESS(af::GraphUtils::AddEdge(gamma->GetAnchor(), node->GetInDataAnchor(4)));
GE_ASSERT_GRAPH_SUCCESS(af::GraphUtils::AddEdge(beta->GetAnchor(), node->GetInDataAnchor(5)));
if (bias_query != nullptr) {
GE_ASSERT_GRAPH_SUCCESS(af::GraphUtils::AddEdge(bias_query->GetAnchor(), node->GetInDataAnchor(6)));
}
if (bias_key != nullptr) {
GE_ASSERT_GRAPH_SUCCESS(af::GraphUtils::AddEdge(bias_key->GetAnchor(), node->GetInDataAnchor(7)));
}
if (bias_value != nullptr) {
GE_ASSERT_GRAPH_SUCCESS(af::GraphUtils::AddEdge(bias_value->GetAnchor(), node->GetInDataAnchor(8)));
}
return EsAttentionLnQKVOutput{
graph.GetEsbTensorFromNode(node, 0),
graph.GetEsbTensorFromNode(node, 1),
graph.GetEsbTensorFromNode(node, 2),
graph.GetEsbTensorFromNode(node, 3),
graph.GetEsbTensorFromNode(node, 4),
graph.GetEsbTensorFromNode(node, 5),
};
}
