EsRaggedTensorToSparseOutput EsRaggedTensorToSparse(EsbTensor **rt_nested_splits, int64_t rt_nested_splits_num, EsbTensor *rt_dense_values, int64_t RAGGED_RANK, af::DataType Tsplits) {
GE_ASSERT_TRUE(af::IntegerChecker<int32_t>::Compat(rt_nested_splits_num));
GE_ASSERT_NOTNULL(rt_dense_values);
auto &graph = rt_dense_values->GetOwner();

auto desc = af::CompliantOpDescBuilder().OpType("RaggedTensorToSparse")
.Name(("RaggedTensorToSparse_" + std::to_string(graph.NextNodeIndex())).c_str())
.IrDefInputs({
{"rt_nested_splits", af::kIrInputDynamic, ""},
{"rt_dense_values", af::kIrInputRequired, ""},
})
.IrDefOutputs({
{"sparse_indices", af::kIrOutputRequired, ""},
{"sparse_values", af::kIrOutputRequired, ""},
{"sparse_dense_shape", af::kIrOutputRequired, ""},
})
.IrDefAttrs({
{
"RAGGED_RANK",
af::kAttrOptional,
"VT_INT",
af::AnyValue::CreateFrom(static_cast<int64_t>(RAGGED_RANK))
},
{
"Tsplits",
af::kAttrOptional,
"VT_DATA_TYPE",
af::AnyValue::CreateFrom(static_cast<af::DataType>(Tsplits))
},
})
.InstanceDynamicInputNum("rt_nested_splits", static_cast<int32_t>(rt_nested_splits_num))
.Build();
GE_ASSERT_NOTNULL(desc);
auto node = graph.GetComputeGraph()->AddNode(desc);
GE_ASSERT_NOTNULL(node);

if ((rt_nested_splits != nullptr) && (rt_nested_splits_num > 0)) {
for (int64_t i = 0; i < rt_nested_splits_num; ++i) {
auto one_rt_nested_splits = rt_nested_splits[i];
GE_ASSERT_NOTNULL(one_rt_nested_splits);
GE_ASSERT_GRAPH_SUCCESS(af::GraphUtils::AddEdge(one_rt_nested_splits->GetAnchor(), node->GetInDataAnchor(0 + i)));
}
}
GE_ASSERT_GRAPH_SUCCESS(af::GraphUtils::AddEdge(rt_dense_values->GetAnchor(), node->GetInDataAnchor(0 + rt_nested_splits_num)));
return EsRaggedTensorToSparseOutput{
graph.GetEsbTensorFromNode(node, 0),
graph.GetEsbTensorFromNode(node, 1),
graph.GetEsbTensorFromNode(node, 2),
};
}
