EsbTensor *EsRoiExtractor(EsbTensor **features, int64_t features_num, EsbTensor *rois, EsbTensor *index, int64_t finest_scale, float roi_scale_factor, const float *spatial_scale, int64_t spatial_scale_num, int64_t pooled_height, int64_t pooled_width, int64_t sample_num, const char *pool_mode, bool aligned) {
GE_ASSERT_TRUE(af::IntegerChecker<int32_t>::Compat(features_num));
GE_ASSERT_NOTNULL(rois);
auto &graph = rois->GetOwner();

auto desc = af::CompliantOpDescBuilder().OpType("RoiExtractor")
.Name(("RoiExtractor_" + std::to_string(graph.NextNodeIndex())).c_str())
.IrDefInputs({
{"features", af::kIrInputDynamic, ""},
{"rois", af::kIrInputRequired, ""},
{"index", af::kIrInputOptional, ""},
})
.IrDefOutputs({
{"y", af::kIrOutputRequired, ""},
})
.IrDefAttrs({
{
"finest_scale",
af::kAttrOptional,
"VT_INT",
af::AnyValue::CreateFrom(static_cast<int64_t>(finest_scale))
},
{
"roi_scale_factor",
af::kAttrOptional,
"VT_FLOAT",
af::AnyValue::CreateFrom(static_cast<float>(roi_scale_factor))
},
{
"spatial_scale",
af::kAttrOptional,
"VT_LIST_FLOAT",
af::AnyValue::CreateFrom(std::vector<float>(spatial_scale, spatial_scale + spatial_scale_num))
},
{
"pooled_height",
af::kAttrOptional,
"VT_INT",
af::AnyValue::CreateFrom(static_cast<int64_t>(pooled_height))
},
{
"pooled_width",
af::kAttrOptional,
"VT_INT",
af::AnyValue::CreateFrom(static_cast<int64_t>(pooled_width))
},
{
"sample_num",
af::kAttrOptional,
"VT_INT",
af::AnyValue::CreateFrom(static_cast<int64_t>(sample_num))
},
{
"pool_mode",
af::kAttrOptional,
"VT_STRING",
af::AnyValue::CreateFrom(std::string(pool_mode))
},
{
"aligned",
af::kAttrOptional,
"VT_BOOL",
af::AnyValue::CreateFrom(static_cast<bool>(aligned))
},
})
.InstanceDynamicInputNum("features", static_cast<int32_t>(features_num))
.Build();
GE_ASSERT_NOTNULL(desc);
auto node = graph.GetComputeGraph()->AddNode(desc);
GE_ASSERT_NOTNULL(node);

if ((features != nullptr) && (features_num > 0)) {
for (int64_t i = 0; i < features_num; ++i) {
auto one_features = features[i];
GE_ASSERT_NOTNULL(one_features);
GE_ASSERT_GRAPH_SUCCESS(af::GraphUtils::AddEdge(one_features->GetAnchor(), node->GetInDataAnchor(0 + i)));
}
}
GE_ASSERT_GRAPH_SUCCESS(af::GraphUtils::AddEdge(rois->GetAnchor(), node->GetInDataAnchor(0 + features_num)));
if (index != nullptr) {
GE_ASSERT_GRAPH_SUCCESS(af::GraphUtils::AddEdge(index->GetAnchor(), node->GetInDataAnchor(1 + features_num)));
}
return graph.GetEsbTensorFromNode(std::move(node), 0);
}
