EsbTensor *EsStage(EsbTensor **values, int64_t values_num, int64_t capacity, int64_t memory_limit, const char *container, const char *shared_name) {
GE_ASSERT_TRUE(af::IntegerChecker<int32_t>::Compat(values_num));
EsbTensor *non_null_in = nullptr;
if (non_null_in == nullptr) {
for (int64_t i = 0; i < values_num; ++i) {
if (values[i] != nullptr) {
non_null_in = values[i];
break;
}
}
}
GE_ASSERT_NOTNULL(non_null_in);
auto &graph = non_null_in->GetOwner();

auto desc = af::CompliantOpDescBuilder().OpType("Stage")
.Name(("Stage_" + std::to_string(graph.NextNodeIndex())).c_str())
.IrDefInputs({
{"values", af::kIrInputDynamic, ""},
})
.IrDefOutputs({
})
.IrDefAttrs({
{
"capacity",
af::kAttrOptional,
"VT_INT",
af::AnyValue::CreateFrom(static_cast<int64_t>(capacity))
},
{
"memory_limit",
af::kAttrOptional,
"VT_INT",
af::AnyValue::CreateFrom(static_cast<int64_t>(memory_limit))
},
{
"container",
af::kAttrOptional,
"VT_STRING",
af::AnyValue::CreateFrom(std::string(container))
},
{
"shared_name",
af::kAttrOptional,
"VT_STRING",
af::AnyValue::CreateFrom(std::string(shared_name))
},
})
.InstanceDynamicInputNum("values", static_cast<int32_t>(values_num))
.Build();
GE_ASSERT_NOTNULL(desc);
auto node = graph.GetComputeGraph()->AddNode(desc);
GE_ASSERT_NOTNULL(node);

if ((values != nullptr) && (values_num > 0)) {
for (int64_t i = 0; i < values_num; ++i) {
auto one_values = values[i];
GE_ASSERT_NOTNULL(one_values);
GE_ASSERT_GRAPH_SUCCESS(af::GraphUtils::AddEdge(one_values->GetAnchor(), node->GetInDataAnchor(0 + i)));
}
}
return graph.GetEsbTensorFromNode(std::move(node), -1);
}
