EsbTensor *EsStringFormat(EsbTensor **x, int64_t x_num, const char *attr_template, const char *placeholder, int64_t summarize) {
GE_ASSERT_TRUE(af::IntegerChecker<int32_t>::Compat(x_num));
EsbTensor *non_null_in = nullptr;
if (non_null_in == nullptr) {
for (int64_t i = 0; i < x_num; ++i) {
if (x[i] != nullptr) {
non_null_in = x[i];
break;
}
}
}
GE_ASSERT_NOTNULL(non_null_in);
auto &graph = non_null_in->GetOwner();

auto desc = af::CompliantOpDescBuilder().OpType("StringFormat")
.Name(("StringFormat_" + std::to_string(graph.NextNodeIndex())).c_str())
.IrDefInputs({
{"x", af::kIrInputDynamic, ""},
})
.IrDefOutputs({
{"y", af::kIrOutputRequired, ""},
})
.IrDefAttrs({
{
"template",
af::kAttrOptional,
"VT_STRING",
af::AnyValue::CreateFrom(std::string(attr_template))
},
{
"placeholder",
af::kAttrOptional,
"VT_STRING",
af::AnyValue::CreateFrom(std::string(placeholder))
},
{
"summarize",
af::kAttrOptional,
"VT_INT",
af::AnyValue::CreateFrom(static_cast<int64_t>(summarize))
},
})
.InstanceDynamicInputNum("x", static_cast<int32_t>(x_num))
.Build();
GE_ASSERT_NOTNULL(desc);
auto node = graph.GetComputeGraph()->AddNode(desc);
GE_ASSERT_NOTNULL(node);

if ((x != nullptr) && (x_num > 0)) {
for (int64_t i = 0; i < x_num; ++i) {
auto one_x = x[i];
GE_ASSERT_NOTNULL(one_x);
GE_ASSERT_GRAPH_SUCCESS(af::GraphUtils::AddEdge(one_x->GetAnchor(), node->GetInDataAnchor(0 + i)));
}
}
return graph.GetEsbTensorFromNode(std::move(node), 0);
}
